1	type Item = { type: string; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const COMPONENT_BLOCK_SIZE = 3;
8	const COMPONENT_BLOCK_PREMIUM = 60;
9	
10	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	
21	const groupBaseAmount = (type: string, count: number): number => {
22	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
23	    return COMPONENT_BLOCK_PREMIUM;
24	  }
25	  return count * BASE_PREMIUM_BY_TYPE[type];
26	};
27	
28	const countByType = (items: Item[]): Map<string, number> =>
29	  items.reduce(
30	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
31	    new Map<string, number>(),
32	  );
33	
34	const basePremium = (items: Item[]): number =>
35	  Array.from(countByType(items)).reduce(
36	    (total, [type, count]) => total + groupBaseAmount(type, count),
37	    0,
38	  );
39	
40	const percentOf = (amount: number, percent: number): number =>
41	  (amount * percent) / 100;
42	
43	const firstInsuranceSurcharge = (base: number): number =>
44	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
45	
46	const CURSE_SURCHARGE_PERCENT = 50;
47	
48	const itemSurcharges = (items: Item[]): number =>
49	  items.reduce((sum, item) => {
50	    const itemBase = BASE_PREMIUM_BY_TYPE[item.type];
51	    return sum + (item.cursed ? percentOf(itemBase, CURSE_SURCHARGE_PERCENT) : 0);
52	  }, 0);
53	
54	const quotePremium = (items: Item[]): number => {
55	  const base = basePremium(items);
56	  return base + itemSurcharges(items) + firstInsuranceSurcharge(base) + PROCESSING_FEE;
57	};
58	
59	const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });
60	
61	export const run = (input: unknown): unknown => {
62	  const { steps } = input as Input;
63	  return { results: steps.map(executeStep) };
64	};
